#include <iostream>

class Point {
private:
    int m_xCoord;
    int m_yCoord;

public:
    // Default constructor
    Point() {
        this->m_xCoord = 0;
        this->m_yCoord = 0;
    }

    // Parameterized constructor
    Point(int initialXValue, int initialYValue) {
        this->m_xCoord = initialXValue;
        this->m_yCoord = initialYValue;
    }

    // Public method to display coordinates
    void displayPoint() {
        std::cout << "(" << this->m_xCoord << ", " << this->m_yCoord << ")";
    }
};

int main() {
    // Test default constructor
    Point p1;
    std::cout << "Point p1 (default): ";
    p1.displayPoint();
    std::cout << std::endl;

    // Test parameterized constructor
    Point p2(10, 20);
    std::cout << "Point p2 (parameterized): ";
    p2.displayPoint();
    std::cout << std::endl;

    // Test with negative coordinates
    Point p3(-5, -8);
    std::cout << "Point p3 (negative): ";
    p3.displayPoint();
    std::cout << std::endl;

    return 0;
}
